// The module-level closure variables (data, videoCache) let us
// change what readData/readVideoCache return per test via reset().

const mockAppStore = vi.hoisted(() => {
	let data = {
		subscriptions: [],
		settings: {},
		redirects: {},
	};
	let videoCache = {
		videos: [],
		lastUpdated: null,
		totalChannels: 0,
		totalVideos: 0,
		channelRefreshes: {},
		shortsStatusById: {},
	};

	return {
		readData: vi.fn(async () => JSON.parse(JSON.stringify(data))),
		writeData: vi.fn(async (d) => {
			data = d;
			return d;
		}),
		updateData: vi.fn(async (_fallback, updater) => {
			const current = JSON.parse(JSON.stringify(data));
			const updated = await updater(current);
			data = updated || current;
			return data;
		}),
