import { vi, describe, it, expect, beforeEach } from 'vitest';

// ── Mock app-store ───────────────────────────────────────────
// Module-level closure captures the mutable state so tests can
// control what readData / readVideoCache return.

const mockAppStore = vi.hoisted(() => {
	let data = {
		subscriptions: [],
		settings: {},
		redirects: {},
	};
	let videoCache = {
		videos: [],
		lastUpdated: null,
		totalChannels: 0,
		totalVideos: 0,
		channelRefreshes: {},
		shortsStatusById: {},
	};

	function deepClone(obj) {
		return JSON.parse(JSON.stringify(obj));
	}

	return {
		readData: vi.fn(async () => deepClone(data)),
		writeData: vi.fn(async (d) => {
			data = d;
			return d;
		}),
		updateData: vi.fn(async (_fallback, updater) => {
			const current = deepClone(data);
			const updated = await updater(current);
			data = updated || current;
			return data;
		}),
		readVideoCache: vi.fn(async () => deepClone(videoCache)),
		writeVideoCache: vi.fn(async (c) => {
			videoCache = c;
			return c;
		}),
		getCurrentRevision: vi.fn(() => 1),
		// Reset internal data for a fresh test
		reset(overrides = {}) {
			data = overrides.data || {
				subscriptions: [],
				settings: {},
				redirects: {},
			};
			videoCache = overrides.videoCache || {
				videos: [],
				lastUpdated: null,
				totalChannels: 0,
				totalVideos: 0,
				channelRefreshes: {},
				shortsStatusById: {},
			};
			this.readData.mockImplementation(async () => deepClone(data));
			this.writeData.mockImplementation(async (d) => {
				data = d;
				return d;
			});
			this.updateData.mockImplementation(async (_fallback, updater) => {
				const current = deepClone(data);
				const updated = await updater(current);
				data = updated || current;
				return data;
			});
			this.readVideoCache.mockImplementation(async () => deepClone(videoCache));
			this.writeVideoCache.mockImplementation(async (c) => {
				videoCache = c;
				return c;
			});
			this.getCurrentRevision.mockImplementation(() => 1);
		},
	};
});

